  ('real-estate-moex-01511', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列何者屬於公平交易法之「不公平競爭」？', '["無正當理由，對他事業給予差別待遇之行為", "以不正當限制交易相對人之事業活動為條件，而與其交易之行為", "事業限制其交易相對人就供給之商品轉售價格之行為", "事業在商品或廣告上為虛偽不實或引人錯誤之表示或表徵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
